            goToMainScreen()
        } else {
            let alert = UIAlertController(title: "Incorrect Password", message: "The password entered is incorrect.", preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "Try Again", style: .default, handler: { [weak self] _ in
